const API_URL = process.env.REACT_APP_API_URL || 'http://localhost/dashboard/api/endpoints';

class ApiService {
  static async request(endpoint, method = 'GET', data = null, options = {}) {
    const token = localStorage.getItem('token');
    const url = endpoint.startsWith('http') ? endpoint : `${API_URL}${endpoint}`;
    
    console.log('Making API request to:', url);
    console.log('Request data:', data);
    
    // Default headers
    const headers = {
      'Authorization': token ? `Bearer ${token}` : '',
      'Accept': 'application/json'
    };

    // Only set Content-Type if not FormData
    if (!(data instanceof FormData)) {
      headers['Content-Type'] = 'application/json';
    }

    // Merge with custom headers from options
    if (options.headers) {
      Object.assign(headers, options.headers);
    }

    const config = {
      method,
      headers,
      credentials: 'include',
    };

    if (data) {
      // Don't stringify if it's FormData
      config.body = data instanceof FormData ? data : JSON.stringify(data);
    }

    try {
      const response = await fetch(url, config);
      console.log('Response status:', response.status);
      
      const text = await response.text();
      console.log('Raw response:', text); // Add this for debugging

      // Check if response contains HTML (error page)
      if (text.includes('<!DOCTYPE html>') || text.includes('<br />')) {
        throw new Error('Received HTML response instead of JSON');
      }

      if (!text) {
        return { message: 'Success' };
      }

      const result = JSON.parse(text);
      if (!response.ok) {
        throw new Error(result.message || `HTTP error! status: ${response.status}`);
      }
      return result;
    } catch (error) {
      console.error('API Error:', error);
      console.error('Failed request URL:', url);
      throw new Error(`Request failed: ${error.message}`);
    }
  }

  static get(endpoint) {
    return this.request(endpoint);
  }

  static post(endpoint, data) {
    return this.request(endpoint, 'POST', data);
  }

  static put(endpoint, data) {
    return this.request(endpoint, 'PUT', data);
  }

  static delete(endpoint) {
    return this.request(endpoint, 'DELETE');
  }

  // Admin Dashboard specific endpoints
  static async getDashboardStats() {
    try {
      const response = await this.get('/admin/dashboard-stats.php');
      
      // Add more robust response validation
      if (!response || typeof response !== 'object') {
        throw new Error('Invalid response format');
      }

      if (response.status === 'error') {
        throw new Error(response.message || 'Failed to fetch dashboard stats');
      }

      // Ensure stats object exists and has required properties
      if (!response.stats || typeof response.stats !== 'object') {
        throw new Error('Invalid stats data format');
      }

      // Provide default values if any stat is missing
      const defaultStats = {
        totalStudents: 0,
        totalTeachers: 0,
        activeClasses: 0,
        monthlyRevenue: 0,
        totalBatches: 0,
        attendanceRate: 0
      };

      return {
        status: 'success',
        stats: { ...defaultStats, ...response.stats }
      };
    } catch (error) {
      console.error('Dashboard stats error:', error);
      throw error;
    }
  }

  static async getBatchStats() {
    return this.get('/admin/batch-stats.php');
  }

  static async getAttendanceOverview() {
    return this.get('/admin/attendance-overview.php');
  }

  // Batch Management endpoints
  static async getBatches() {
    return this.get('/batches/get-all.php');
  }

  static async createBatch(batchData) {
    return this.post('/batches/create.php', batchData);
  }

  static async updateBatch(id, batchData) {
    return this.put(`/batches/update.php?id=${id}`, batchData);
  }

  static async deleteBatch(id) {
    return this.delete(`/batches/delete.php?id=${id}`);
  }

  static async getBatchDetails(id) {
    return this.get(`/batches/get-details.php?id=${id}`);
  }
}

export default ApiService;
